SELECT * FROM pol_policy

    AND policy_code = #{policyCode}
    AND active = #{active}

ORDER BY policy_code ASC, effective_from DESC NULLS LAST, id DESC

SELECT COUNT(*) FROM pol_policy
WHERE policy_code = #{policyCode}
AND id <> #{excludeId}

SELECT * FROM pol_policy_assignment
WHERE policy_id = #{policyId}
ORDER BY COALESCE(priority, 0) DESC, id ASC

